class DiscountCalculator {
    static int calculateDiscountPrice(int price, int discountAmount) {
        return price - discountAmount;
    }
}

public class Main {
    public static void main(String[] args) {
        int result = DiscountCalculator.calculateDiscountPrice(10000, 1500);
        System.out.println(result);
    }
}

class Account {
    static final String BANK_NAME = "Java Bank";
    static int accountCount = 0;

    String owner;
    int balance;

    Account(String owner, int balance) {
        this.owner = owner;
        this.balance = balance;
        accountCount++;
    }

    void printInfo() {
        System.out.println(BANK_NAME);
        System.out.println(owner + " " + balance);
    }
}

public class Main {
    public static void main(String[] args) {
        Account a1 = new Account("Kim", 10000);
        Account a2 = new Account("Lee", 20000);

        a1.printInfo();
        a2.printInfo();
        System.out.println(Account.accountCount);
    }
}
